/**
 * @name Untrusted ImageMath expression reaching eval/exec
 * @description Tracks data from ImageMath.eval function parameters into eval/exec/compile calls.
 * @kind path-problem
 * @problem.severity error
 * @id py/pillow-imagemath-untrusted-to-eval
 * @tags security
 *       external/cwe/cwe-094
 *       external/cwe/cwe-095
 */

import python
import semmle.python.dataflow.new.DataFlow
import semmle.python.dataflow.new.TaintTracking
import semmle.python.ApiGraphs

module ImageMathConfig implements DataFlow::ConfigSig {
  predicate isSource(DataFlow::Node source) {
    exists(API::CallNode call |
      call = API::moduleImport("PIL.ImageMath").getMember("eval").getACall() and
      source = call.getArg(0)
    )
  }

  predicate isSink(DataFlow::Node sink) {
    exists(API::CallNode call |
      call = API::builtin(["eval", "exec", "compile"]).getACall() and
      sink = call.getArg(0)
    )
  }
}

module ImageMathFlow = TaintTracking::Global<ImageMathConfig>;
import ImageMathFlow::PathGraph

from ImageMathFlow::PathNode source, ImageMathFlow::PathNode sink
where ImageMathFlow::flowPath(source, sink)
select sink.getNode(), source, sink, "ImageMath expression flows into dynamic code execution ($@).", source, "expression"
